class Solution:
    def solve(self, layout, itemHeights, includeGridLineHeight):
        # Initialize the maximum row height to 0
        maxHeight = 0
        # Iterate over each row
        for i in range(0, len(itemHeights), layout.columns):
            # Initialize the current row height to 0
            rowHeight = 0
            # Iterate over each item in the row
            for j in range(layout.columns):
                # Add the item height to the current row height
                rowHeight += itemHeights[i + j]
            # If the current row height is greater than the maximum row height, update the maximum row height
            if rowHeight > maxHeight:
                maxHeight = rowHeight
        # If the includeGridLineHeight flag is true, add the grid line height to the maximum row height
        if includeGridLineHeight:
            maxHeight += layout.gridLineHeight
        # Return the maximum row height
        return maxHeight
